  messageId: string;
  entities: ExtractedEntity[];
  relationships: ExtractedRelationship[];
};

export type OnboardingSeedEvent = {
  type: "onboarding_seed";
  messageId: string;
  seeds: OnboardingSeedItem[];
};

export type OnboardingStateEvent = {
  type: "onboarding_state";
  messageId: string;
  onboardingState: OnboardingState;
};

export type ObservationEvent = {
  type: "observation";
  messageId: string;
  action: "created" | "acknowledged" | "resolved";
  observation: ObservationSummary;
};

export type DoneEvent = {
  type: "done";
  messageId: string;
};

export type ErrorEvent = {
  type: "error";
  messageId: string;
  error: string;
};

export type StreamEvent =
  | TokenEvent
  | AssistantMessageEvent
  | ExtractionEvent
  | OnboardingSeedEvent
  | OnboardingStateEvent
  | ObservationEvent
  | DoneEvent
  | ErrorEvent;

export type SearchEntityResponse = {
  id: string;
  kind: EntityKind;
  text: string;
  confidence: number;
  sourceId: string;
  sourceKind: SourceKind;
};

// --- Graph view types ---

export type ReagraphNode = {
  id: string;
  label: string;
  fill: string;
  data: {
    kind: EntityKind;
    connectionCount: number;
    status?: string;
  };
};

export type ReagraphEdge = {
  id: string;
  source: string;
  target: string;
  label: string;
  data: {
    type: string;
    confidence: number;
  };
};

export type GraphResponse = {
  nodes: ReagraphNode[];
  edges: ReagraphEdge[];
};

export type EntityDetailResponse = {
  entity: {
    id: string;
    kind: EntityKind;
    name: string;
    data: Record<string, unknown>;
  };
  relationships: Array<{
    id: string;
    kind: EntityKind;
    name: string;
    relationKind: string;
    direction: "incoming" | "outgoing";
    confidence: number;
  }>;
  provenance: Array<{
    sourceId: string;
    sourceKind: SourceKind;
    confidence: number;
    extractedAt: string;
    evidence?: string;
    evidenceSource?: string;
    resolvedFrom?: string;
    fromText?: string;
  }>;
};

export type BranchConversationRequest = {
  messageId: string;
};

export type BranchConversationResponse = {
  conversationId: string;
  parentConversationId: string;
  branchPointMessageId: string;
};

export type GovernanceTier = "blocking" | "review" | "awareness";

export type GovernanceFeedAction = {
  action: "confirm" | "override" | "acknowledge" | "resolve" | "complete" | "discuss";
  label: string;
};

export type GovernanceFeedItem = {
  id: string;               // composite: "decision:<uuid>:provisional"
  tier: GovernanceTier;
  entityId: string;          // "decision:<uuid>"
  entityKind: EntityKind;
  entityName: string;
  reason: string;            // "Provisional decision awaiting confirmation"
  status: string;
  project?: string;
  category?: EntityCategory;
  priority?: EntityPriority;
  severity?: ObservationSeverity;
  createdAt: string;
  actions: GovernanceFeedAction[];
  conflictTarget?: {         // for conflict items
    entityId: string;
    entityKind: EntityKind;
    entityName: string;
  };
};

export type GovernanceFeedResponse = {
  blocking: GovernanceFeedItem[];
  review: GovernanceFeedItem[];
  awareness: GovernanceFeedItem[];
  updatedAt: string;
};

export type EntityActionRequest = {
  action: "confirm" | "override" | "complete" | "set_priority" | "acknowledge" | "resolve";
  notes?: string;
  newSummary?: string;
  priority?: EntityPriority;
};

